class Solution {
public:
    long long mostPoints(vector<vector<int>>& questions) {
        int n = questions.size();
        vector<int> points(n, 0);
        vector<int> brainpower(n, 0);

        for (int i = 0; i < n; i++) {
            points[i] = questions[i][0];
            brainpower[i] = questions[i][1];
        }

        long long maxPoints = 0;
        for (int i = 1; i < n; i++) {
            if (brainpower[i - 1] >= brainpower[i]) {
                maxPoints = max(maxPoints, points[i] + questions[i][0]);
                brainpower[i] = questions[i][1];
            }
        }

        return maxPoints;
    }
};
```

